const express = require("express");
const cors = require("cors");

const app = express();
app.use(cors());
app.use(express.json());

// --- In-memory DB ---
let cards = [
  {
    id: "c1",
    name: "Ace of Spades",
    suit: "Spades",
    rank: "Ace",
    condition: "Mint",
    quantity: 1,
    isFoil: false,
    createdAt: new Date().toISOString(),
  },
];

// Helpers
const validSuits = ["Hearts", "Diamonds", "Clubs", "Spades"];
const validRanks = ["Ace","2","3","4","5","6","7","8","9","10","Jack","Queen","King"];

function validateCard(body) {
  const errors = [];
  const { name, suit, rank, condition, quantity, isFoil } = body;

  if (!name || typeof name !== "string") errors.push("name is required (string)");
  if (!suit || !validSuits.includes(suit)) errors.push(`suit must be one of: ${validSuits.join(", ")}`);
  if (!rank || !validRanks.includes(rank)) errors.push(`rank must be one of: ${validRanks.join(", ")}`);
  if (condition && typeof condition !== "string") errors.push("condition must be a string");
  if (quantity !== undefined && (!Number.isInteger(quantity) || quantity < 0)) errors.push("quantity must be an integer >= 0");
  if (isFoil !== undefined && typeof isFoil !== "boolean") errors.push("isFoil must be boolean");

  return errors;
}

function makeId() {
  return "c" + Math.random().toString(16).slice(2, 10);
}

// --- Routes ---

// Health
app.get("/", (req, res) => res.json({ status: "ok", service: "playing-card-api" }));

// CREATE card
app.post("/api/cards", (req, res) => {
  const errors = validateCard(req.body);
  if (errors.length) return res.status(400).json({ errors });

  const newCard = {
    id: makeId(),
    name: req.body.name.trim(),
    suit: req.body.suit,
    rank: req.body.rank,
    condition: req.body.condition?.trim() || "Good",
    quantity: req.body.quantity ?? 1,
    isFoil: req.body.isFoil ?? false,
    createdAt: new Date().toISOString(),
  };

  cards.unshift(newCard);
  res.status(201).json(newCard);
});

// READ all cards (supports filters)
app.get("/api/cards", (req, res) => {
  const { suit, rank, q } = req.query;
  let result = [...cards];

  if (suit) result = result.filter((c) => c.suit === suit);
  if (rank) result = result.filter((c) => c.rank === rank);
  if (q) {
    const s = String(q).toLowerCase();
    result = result.filter((c) => c.name.toLowerCase().includes(s));
  }

  res.json(result);
});

// READ one card
app.get("/api/cards/:id", (req, res) => {
  const card = cards.find((c) => c.id === req.params.id);
  if (!card) return res.status(404).json({ message: "Card not found" });
  res.json(card);
});

// UPDATE card (partial)
app.patch("/api/cards/:id", (req, res) => {
  const idx = cards.findIndex((c) => c.id === req.params.id);
  if (idx === -1) return res.status(404).json({ message: "Card not found" });

  const merged = { ...cards[idx], ...req.body };
  const errors = validateCard(merged);
  if (errors.length) return res.status(400).json({ errors });

  cards[idx] = {
    ...cards[idx],
    ...req.body,
    name: req.body.name ? req.body.name.trim() : cards[idx].name,
    condition: req.body.condition ? req.body.condition.trim() : cards[idx].condition,
  };

  res.json(cards[idx]);
});

// DELETE card
app.delete("/api/cards/:id", (req, res) => {
  const before = cards.length;
  cards = cards.filter((c) => c.id !== req.params.id);
  if (cards.length === before) return res.status(404).json({ message: "Card not found" });
  res.json({ message: "Card deleted" });
});

const PORT = process.env.PORT || 5000;
app.listen(PORT, () => console.log(`API running on http://localhost:${PORT}`));